export const GAME_WIDTH = 800;
export const GAME_HEIGHT = 600;

export const PLAYER_SPEED = 250;
export const PLAYER_BULLET_SPEED = 500;
export const FIRE_RATE = 250; // ms between shots

export const ENEMY_SPEED_BASE = 100;
export const SCORE_PER_ENEMY = 10;
export const MAX_LIVES = 3;

export const WAVES = [
  { wave: 1, count: 5, speedMultiplier: 1 },
  { wave: 2, count: 8, speedMultiplier: 1.3 },
  { wave: 3, count: 12, speedMultiplier: 1.6 },
];

import { create } from 'zustand';

interface GameState {
  score: number;
  lives: number;
  wave: number;
  gameStatus: 'menu' | 'playing' | 'gameover' | 'victory';
  addScore: (points: number) => void;
  setLives: (lives: number) => void;
  setWave: (wave: number) => void;
  setGameStatus: (status: 'menu' | 'playing' | 'gameover' | 'victory') => void;
  resetGame: () => void;
}

export const useGameStore = create<GameState>((set) => ({
  score: 0,
  lives: 3,
  wave: 1,
  gameStatus: 'menu',
  addScore: (points) => set((state) => ({ score: state.score + points })),
  setLives: (lives) => set({ lives }),
  setWave: (wave) => set({ wave }),
  setGameStatus: (status) => set({ gameStatus: status }),
  resetGame: () => set({ score: 0, lives: 3, wave: 1, gameStatus: 'playing' }),
}));

import { Events } from 'phaser';

// Global EventBus for Scene-React communication
export const EventBus = new Events.EventEmitter();

export interface WaveConfig {
  wave: number;
  count: number;
  speedMultiplier: number;
}

