export class Boot extends Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    // 载入所有必需的资源
    this.load.image('player_ship', ASSETS.playerShip);
    this.load.spritesheet('player_ship_flame', ASSETS.playerShipFlame, { frameWidth: 17, frameHeight: 32 });
    this.load.image('enemy_unit', ASSETS.enemyUnit);
    this.load.image('enemy_mothership', ASSETS.enemyMothership);
    this.load.image('bullet', ASSETS.bullet);
    this.load.spritesheet('explosion', ASSETS.explosion, { frameWidth: 100, frameHeight: 100 });
    this.load.spritesheet('laser_explosion_small', ASSETS.laserExplosionSmall, { frameWidth: 64, frameHeight: 64 });
    this.load.image('background', ASSETS.background);
    this.load.image('menu_background', ASSETS.menuBackground);
    this.load.image('hud_life_indicator', ASSETS.hudLifeIndicator);
    this.load.image('hud_panel', ASSETS.hudPanel);
    this.load.image('btn_start', ASSETS.btnStart);
    this.load.image('btn_restart', ASSETS.btnRestart);

    // 错误处理后退垫
    this.load.on('loaderror', (file: any) => {
      const g = this.add.graphics();
      g.fillGradientStyle(0x667788, 0x334455, 0x334455, 0x667788);
      g.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
      g.generateTexture(file.key, GAME_WIDTH, GAME_HEIGHT);
      g.destroy();
    });
  }

  create() {
    // 注册全局动画
    this.anims.create({ key: 'flame', frames: this.anims.generateFrameNumbers('player_ship_flame', { start: 0, end: 6 }), frameRate: 12, repeat: -1 });
    this.anims.create({ key: 'explode', frames: this.anims.generateFrameNumbers('explosion', { start: 0, end: 8 }), frameRate: 15, repeat: 0 });
    this.anims.create({ key: 'hit_flash', frames: this.anims.generateFrameNumbers('laser_explosion_small', { start: 0, end: 7 }), frameRate: 20, repeat: 0 });

    this.scene.start('MainMenu');
  }
}

