import { Scene } from 'phaser';
import { EventBus } from '../EventBus';
import { useGameStore } from '../store/gameStore';
import {
  GAME_WIDTH,
  GAME_HEIGHT,
  PLAYER_SPEED,
  PLAYER_BULLET_SPEED,
  FIRE_RATE,
  ENEMY_SPEED_BASE,
  SCORE_PER_ENEMY,
  WAVES,
} from '../constants';

export class GameScene extends Scene {
  private player!: Phaser.Physics.Arcade.Sprite;
  private enemies!: Phaser.Physics.Arcade.Group;
  private bullets!: Phaser.Physics.Arcade.Group;

  private cursors!: Phaser.Types.Input.Keyboard.CursorKeys;
  private wasd!: {
    up: Phaser.Input.Keyboard.Key;
    down: Phaser.Input.Keyboard.Key;
    left: Phaser.Input.Keyboard.Key;
    right: Phaser.Input.Keyboard.Key;
  };
  private spaceKey!: Phaser.Input.Keyboard.Key;

  private lastFired: number = 0;
  private isInvulnerable: boolean = false;
  private isGameOver: boolean = false;

  private currentWaveIndex: number = 0;
  private enemiesToSpawn: number = 0;
  private waveSpeedMultiplier: number = 1;

  constructor() {
    super('GameScene');
  }

  create() {
    this.isGameOver = false;
    this.lastFired = 0;
    this.isInvulnerable = false;

    // 初始化状态
    useGameStore.getState().resetGame();
    this.currentWaveIndex = 0;

    const { width, height } = this.scale;
    this.add.image(width / 2, height / 2, 'background').setDisplaySize(width, height);

    // 玩家
    this.player = this.physics.add.sprite(width / 2, height / 2, 'player_ship');
    this.player.setCollideWorldBounds(false);
    this.player.setScale(0.8);
    this.player.play('flame');
    // 飞船图片默认朝上，Phaser 中 0 度朝右，所以将其设为朝上需要 -90度（也就是设 rotate -PI/2）
    // 或者我们直接在发子弹时处理

    // 组
    this.enemies = this.physics.add.group();
    this.bullets = this.physics.add.group();

    // 输入
    if (this.input.keyboard) {
      this.cursors = this.input.keyboard.createCursorKeys();
      this.wasd = this.input.keyboard.addKeys({
        up: Phaser.Input.Keyboard.KeyCodes.W,
        down: Phaser.Input.Keyboard.KeyCodes.S,
        left: Phaser.Input.Keyboard.KeyCodes.A,
        right: Phaser.Input.Keyboard.KeyCodes.D
      }) as any;
      this.spaceKey = this.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.SPACE);
    }

    // 碰撞
    this.physics.add.overlap(this.bullets, this.enemies, this.handleBulletHitEnemy, undefined, this);
    this.physics.add.overlap(this.player, this.enemies, this.handlePlayerHitEnemy, undefined, this);

    // 启动第一波
    this.startWave();

    // 监听重新开始场景事件
    this.events.once('shutdown', this.shutdown, this);
  }

  shutdown() {
    // 清理事件，如果有的话
  }

  startWave() {
    if (this.currentWaveIndex >= WAVES.length) {
      // 胜利
      this.isGameOver = true;
      useGameStore.getState().setGameStatus('victory');

      // 延迟一会显示胜利
      this.time.delayedCall(1500, () => {
        EventBus.emit('scene-changed', { key: 'GameOver' });
        this.scene.start('GameOver');
      });
      return;
    }

    const waveConfig = WAVES[this.currentWaveIndex];
    useGameStore.getState().setWave(waveConfig.wave);
    this.enemiesToSpawn = waveConfig.count;
    this.waveSpeedMultiplier = waveConfig.speedMultiplier;

    // 波次提示文本
    const waveText = this.add.text(GAME_WIDTH / 2, GAME_HEIGHT / 2, `第 ${waveConfig.wave} 波`, {
      fontSize: '64px',
      color: '#00ffff',
      fontStyle: 'bold'
    }).setOrigin(0.5);

    this.time.delayedCall(1500, () => {
      waveText.destroy();
      this.spawnEnemiesPeriodically();
    });
  }

  spawnEnemiesPeriodically() {
    if (this.isGameOver || this.enemiesToSpawn <= 0) return;

    // 随机边缘生成
    const isHorizontal = Phaser.Math.Between(0, 1) === 0;
    let spawnX, spawnY;

    if (isHorizontal) {
      spawnX = Phaser.Math.Between(0, 1) === 0 ? -50 : GAME_WIDTH + 50;
      spawnY = Phaser.Math.Between(0, GAME_HEIGHT);
    } else {
      spawnX = Phaser.Math.Between(0, GAME_WIDTH);
      spawnY = Phaser.Math.Between(0, 1) === 0 ? -50 : GAME_HEIGHT + 50;
    }

    const isBoss = this.currentWaveIndex === WAVES.length - 1 && Phaser.Math.Between(0, 3) === 0;
    const enemyKey = isBoss ? 'enemy_mothership' : 'enemy_unit';

    const enemy = this.enemies.create(spawnX, spawnY, enemyKey) as Phaser.Physics.Arcade.Sprite;
    enemy.setScale(isBoss ? 1 : 0.7);
    enemy.setCollideWorldBounds(false);

    // 给敌人一点初始生命值
    enemy.setData('hp', isBoss ? 3 : 1);

    this.enemiesToSpawn--;

    // 延迟生成下一个
    if (this.enemiesToSpawn > 0) {
      this.time.delayedCall(800 - this.currentWaveIndex * 150, () => this.spawnEnemiesPeriodically());
    }
  }

  handleBulletHitEnemy(b: any, e: any) {
    if (this.isGameOver) return;

    const bullet = b as Phaser.Physics.Arcade.Sprite;
    const enemy = e as Phaser.Physics.Arcade.Sprite;

    bullet.destroy();

    let hp = enemy.getData('hp') - 1;
    if (hp > 0) {
      enemy.setData('hp', hp);
      // 闪白
      enemy.setTint(0xffffff);
      this.time.delayedCall(100, () => {
        if (enemy && enemy.active) enemy.clearTint();
      });
      // 命中特效
      const flash = this.add.sprite(enemy.x, enemy.y, 'laser_explosion_small');
      flash.play('hit_flash');
      flash.on('animationcomplete', () => flash.destroy());
    } else {
      // 销毁
      const x = enemy.x;
      const y = enemy.y;
      enemy.destroy();

      const flash = this.add.sprite(x, y, 'laser_explosion_small');
      flash.play('hit_flash');
      flash.on('animationcomplete', () => flash.destroy());

      const boom = this.add.sprite(x, y, 'explosion');
      boom.play('explode');
      boom.on('animationcomplete', () => boom.destroy());

      useGameStore.getState().addScore(SCORE_PER_ENEMY);

      // 检查本波是否结束
      if (this.enemiesToSpawn <= 0 && this.enemies.countActive(true) === 0) {
        this.currentWaveIndex++;
        this.time.delayedCall(1000, () => this.startWave());
      }
    }
  }

  handlePlayerHitEnemy(p: any, e: any) {
    if (this.isInvulnerable || this.isGameOver) return;

    this.isInvulnerable = true;

    const store = useGameStore.getState();
    const newLives = store.lives - 1;
    store.setLives(newLives);

    // 闪烁效果
    this.tweens.add({
      targets: this.player,
      alpha: 0.2,
      duration: 100,
      yoyo: true,
      repeat: 10,
      onComplete: () => {
        if (this.player && this.player.active) {
          this.player.setAlpha(1);
          this.isInvulnerable = false;
        }
      }
    });

    if (newLives <= 0) {
      this.isGameOver = true;
      this.player.setVisible(false); // 不显示玩家
      (this.player.body as Phaser.Physics.Arcade.Body).enable = false;

      const boom = this.add.sprite(this.player.x, this.player.y, 'explosion');
      boom.setScale(1.5);
      boom.play('explode');
      boom.on('animationcomplete', () => boom.destroy());

      store.setGameStatus('gameover');

      this.time.delayedCall(1500, () => {
        EventBus.emit('scene-changed', { key: 'GameOver' });
        this.scene.start('GameOver');
      });
    }
  }

  update(time: number, delta: number) {
    if (this.isGameOver) return;

    // --- 玩家移动 ---
    let vx = 0;
    let vy = 0;

    if (this.cursors.left.isDown || this.wasd.left.isDown) vx = -1;
    else if (this.cursors.right.isDown || this.wasd.right.isDown) vx = 1;

    if (this.cursors.up.isDown || this.wasd.up.isDown) vy = -1;
    else if (this.cursors.down.isDown || this.wasd.down.isDown) vy = 1;

    const vec = new Phaser.Math.Vector2(vx, vy).normalize();
    this.player.setVelocity(vec.x * PLAYER_SPEED, vec.y * PLAYER_SPEED);

    if (vec.lengthSq() > 0) {
      // Phaser 中 0度向右，飞船图片默认朝上（-90度）
      // 使用 vec 计算朝向
      this.player.setRotation(vec.angle() + Math.PI / 2);
    }

    // --- 屏幕边缘穿越 ---
    Phaser.Actions.WrapInRectangle([this.player], this.physics.world.bounds, 32);

    // --- 射击 ---
    if (this.spaceKey.isDown && time > this.lastFired) {
      this.shoot();
      this.lastFired = time + FIRE_RATE;
    }

    // --- 敌人移动 ---
    this.enemies.getChildren().forEach((child) => {
      const enemy = child as Phaser.Physics.Arcade.Sprite;
      if (enemy.active && this.player.active) {
        // 简单追踪
        this.physics.moveToObject(enemy, this.player, ENEMY_SPEED_BASE * this.waveSpeedMultiplier);
        enemy.setRotation(Phaser.Math.Angle.Between(enemy.x, enemy.y, this.player.x, this.player.y) + Math.PI / 2);
      }
    });

    // --- 清理飞出屏幕过远的子弹 ---
    this.bullets.getChildren().forEach((child) => {
      const bullet = child as Phaser.Physics.Arcade.Sprite;
      if (
        bullet.x < -100 || bullet.x > GAME_WIDTH + 100 ||
        bullet.y < -100 || bullet.y > GAME_HEIGHT + 100
      ) {
        bullet.destroy();
      }
    });
  }

  shoot() {
    if (this.isGameOver) return;

    // 寻找最近敌人
    let targetEnemy: Phaser.GameObjects.GameObject | null = null;
    let minDist = Infinity;

    this.enemies.getChildren().forEach((child) => {
      const enemy = child as Phaser.Physics.Arcade.Sprite;
      if (enemy.active) {
        const dist = Phaser.Math.Distance.Between(this.player.x, this.player.y, enemy.x, enemy.y);
        if (dist < minDist) {
          minDist = dist;
          targetEnemy = enemy;
        }
      }
    });

    let angle = 0;
    if (targetEnemy) {
      const e = targetEnemy as Phaser.Physics.Arcade.Sprite;
      angle = Phaser.Math.Angle.Between(this.player.x, this.player.y, e.x, e.y);
    } else {
      // 没敌人时按玩家当前朝向发射
      angle = this.player.rotation - Math.PI / 2;
    }

    const bullet = this.bullets.create(this.player.x, this.player.y, 'bullet') as Phaser.Physics.Arcade.Sprite;
    bullet.setScale(0.8);
    // 子弹图片朝上
    bullet.setRotation(angle + Math.PI / 2);
    this.physics.velocityFromRotation(angle, PLAYER_BULLET_SPEED, bullet.body.velocity);
  }
}

